import type { Node } from 'jsonc-parser'

import { buildTree, parseTreeWithoutParent } from '../utils/json'
import type { AbsolutePath } from '../utils/types'
import type { IContentLoader } from './loader'
import type { IContentWatcher, IContentWatcherController } from './watch'

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export class ContentJson<T = any> {
  loader: IContentLoader
  watcher: IContentWatcher
  file: AbsolutePath
  changed: (node?: Node, obj?: T) => void | Promise<void>
  node?: Node
  object?: T

  dirty: boolean
  watcherCtrl?: IContentWatcherController
  duringFlush: boolean
  flushResolve: (() => void)[]
  needFlush: boolean

  constructor(
    loader: IContentLoader,
    watcher: IContentWatcher,
    file: AbsolutePath,
    changed: (node?: Node, obj?: T) => void | Promise<void>
  ) {
    this.loader = loader
    this.watcher = watcher
    this.file = file
    this.changed = changed

    this.dirty = true
    this.duringFlush = false
    this.flushResolve = []
    this.needFlush = false

    this.load()
  }

  async load() {
    this.watcherCtrl?.stop()
    this.dirty = true

    this.watcherCtrl = await this.watcher.watch(this.file, true, {
      filter: (_file, _isdir) => {
        return true
      },
      fileAdded: _file => {
        this.dirty = true
        this.dispatchFlush()
      },
      fileChanged: _file => {
        this.dirty = true
        this.dispatchFlush()
      },
      fileDeleted: _file => {
        this.dirty = true
        this.dispatchFlush()
      }
    })
    await this.flush()
  }

  stop() {
    this.watcherCtrl?.stop()
  }

  async flush() {
    if (this.duringFlush) {
      return new Promise<void>(resolve => {
        this.flushResolve.push(resolve)
      })
    }

    this.duringFlush = true
    this.needFlush = false

    if (this.dirty) {
      const content = await this.loader.get(this.file)
      if (typeof content === 'string') {
        this.node = parseTreeWithoutParent(content)
      } else {
        this.node = undefined
      }
      if (this.node) {
        this.object = buildTree(this.node) as T
      } else {
        this.object = undefined
      }

      await this.changed(this.node, this.object)

      this.dirty = false
    }

    const resolves = this.flushResolve
    this.flushResolve = []

    this.duringFlush = false

    process.nextTick(() => {
      for (const func of resolves) {
        func()
      }
    })

    if (this.needFlush) {
      setTimeout(() => {
        this.flush()
      }, 100)
    }
  }

  dispatchFlush(timeout = 100) {
    if (this.needFlush) {
      return
    }
    this.needFlush = true
    setTimeout(() => {
      this.flush()
    }, timeout)
  }
}
